import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface RecentContact {
  name: string;
  lastMessage: string;
  time: string;
}

interface MessageVolume {
  hour: string;
  messages: number;
}

interface MessagingData {
  unreadConversations: number;
  recentContacts: RecentContact[];
  messageVolume: MessageVolume[];
}

export default function Widget() {
  const data = response.data as MessagingData;
  const meta = response.meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: meta.theme === 'dark' ? '#374151' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: meta.accentColor }}>
              ChatEase Overview
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Unread Conversations: {data.unreadConversations}
            </Typography>
          </Box>

          <Grid container spacing={1}>
            {data.recentContacts.map((contact, index) => (
              <Grid item xs={12} key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Box>
                    <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 500 }}>
                      {contact.name}
                    </Typography>
                    <Typography variant="caption" sx={{ color: '#9CA3AF' }}>
                      {contact.lastMessage}
                    </Typography>
                  </Box>
                  <Typography variant="caption" sx={{ color: '#D1D5DB' }}>
                    {contact.time}
                  </Typography>
                </Stack>
              </Grid>
            ))}
          </Grid>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: data.messageVolume.map(v => v.messages),
                  color: meta.accentColor,
                  label: 'Messages',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.messageVolume.map(v => v.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'messages' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsYAxis
                axisId="messages"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
